-- ============================================
-- T4: Learning Content → Database Migration
-- ============================================
-- Moves hardcoded learning modules & lessons into DB
-- so admins can manage content without code deploys.

-- ─── Tables ────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS learning_modules (
  id         TEXT PRIMARY KEY,
  role       TEXT NOT NULL CHECK (role IN ('agent','manager','admin')),
  title      TEXT NOT NULL,
  description TEXT NOT NULL,
  icon       TEXT NOT NULL DEFAULT 'BookOpen',
  sort_order INT  NOT NULL DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS learning_lessons (
  id               SERIAL PRIMARY KEY,
  module_id        TEXT NOT NULL REFERENCES learning_modules(id) ON DELETE CASCADE,
  slug             TEXT NOT NULL UNIQUE,
  title            TEXT NOT NULL,
  duration         TEXT NOT NULL DEFAULT '3 мин',
  sections         JSONB NOT NULL DEFAULT '[]',
  next_action_label TEXT,
  next_action_href  TEXT,
  sort_order       INT  NOT NULL DEFAULT 0,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX idx_learning_modules_role ON learning_modules(role);
CREATE INDEX idx_learning_lessons_module ON learning_lessons(module_id);

