  ('agent-docs',    'agent', 'Документы',        'Загрузка и управление документами по лидам',                 'FileText',      2),
  ('agent-comms',   'agent', 'Коммуникации',     'Чат с менеджером и Telegram-интеграция',                     'MessageSquare', 3),
  ('agent-faq',     'agent', 'Частые вопросы',   'Ответы на типичные вопросы агентов',                         'HelpCircle',    4);

-- ─── AGENT lessons ────────────────────────────────────

INSERT INTO learning_lessons (module_id, slug, title, duration, sections, next_action_label, next_action_href, sort_order) VALUES
-- agent-start
('agent-start', 'agent-overview', 'Обзор кабинета агента', '3 мин',
 '[{"heading":"Что вы видите после входа","body":"После авторизации вы попадаете на Дашборд — главную страницу агента. Здесь отображается ваша ключевая статистика: количество активных лидов, непрочитанные сообщения, общий заработок и конверсия."},{"heading":"Навигация","body":"В левом меню расположены основные разделы:\n\n• **Дашборд** — сводка по вашей работе\n• **Лиды** — список ваших клиентов\n• **Финансы** — выплаты и баланс\n• **Документы** — загруженные файлы\n• **Сообщения** — чат с менеджером\n• **Профиль** — личные данные и Telegram"},{"heading":"Что делать первым","body":"1. Проверьте свой профиль — убедитесь, что данные актуальны\n2. Подключите Telegram для получения уведомлений\n3. Создайте первый лид"}]',
 'Перейти в Профиль', '/agent/profile', 0),

('agent-start', 'agent-create-lead', 'Как создать лид', '3 мин',
 '[{"heading":"Что такое лид","body":"Лид — это потенциальный клиент, которого вы нашли и передаёте в работу. За каждого клиента, чей лид дойдёт до статуса «Закрыт (выигран)», вы получаете комиссию."},{"heading":"Создание лида","body":"1. Перейдите в раздел **Лиды**\n2. Нажмите кнопку **«Новый лид»**\n3. Заполните форму:\n   • ФИО клиента (обязательно)\n   • Телефон (обязательно)\n   • Email\n   • Город\n   • Источник (откуда пришёл клиент)\n   • Комментарий\n4. Нажмите **«Создать»**"},{"heading":"Что происходит после создания","body":"Лид появляется в вашем списке со статусом «Новый». Менеджер видит его в своём кабинете и начинает работу с клиентом. Вы можете отслеживать статус лида в реальном времени."}]',
 'Создать лид', '/agent/leads', 1),

('agent-start', 'agent-lead-statuses', 'Статусы лидов', '2 мин',
 '[{"heading":"Воронка лидов","body":"Каждый лид проходит через воронку статусов. Менеджер переводит лид по этапам:\n\n• **Новый** — лид только создан\n• **Контакт** — менеджер связался с клиентом\n• **Квалифицирован** — подтверждён интерес клиента\n• **Предложение** — клиенту направлено коммерческое предложение\n• **Переговоры** — идёт обсуждение условий\n• **Закрыт (выигран)** — сделка состоялась, вы получаете выплату\n• **Закрыт (проигран)** — сделка не состоялась"},{"heading":"Что вы можете делать","body":"Вы видите текущий статус каждого лида в списке и на странице лида. При изменении статуса вам придёт уведомление в Telegram (если подключён)."}]',
 'Посмотреть мои лиды', '/agent/leads', 2),

-- agent-finance
('agent-finance', 'agent-payouts', 'Как работают выплаты', '3 мин',
 '[{"heading":"Когда создаётся выплата","body":"Выплата создаётся **автоматически**, когда менеджер переводит ваш лид в статус «Закрыт (выигран)». Сумма выплаты рассчитывается как процент от стоимости сделки (по умолчанию 30%)."},{"heading":"Статусы выплат","body":"• **Ожидает** — выплата создана, ожидает обработки\n• **В обработке** — выплата взята в работу администратором\n• **Оплачено** — деньги перечислены\n• **Отклонено** — выплата отклонена (с указанием причины)"},{"heading":"Где смотреть","body":"Раздел **Финансы** показывает:\n• Общий баланс (ожидает + в обработке + выплачено)\n• Список всех ваших выплат с датами и статусами\n\nПри изменении статуса выплаты вам придёт уведомление в Telegram."}]',
 'Открыть Финансы', '/agent/finance', 0),

-- agent-docs
('agent-docs', 'agent-upload-docs', 'Как загрузить документ', '2 мин',
 '[{"heading":"Зачем нужны документы","body":"Для каждого лида могут потребоваться документы: договоры, акты, доверенности. Вы загружаете их через платформу, и менеджер получает к ним доступ."},{"heading":"Как загрузить","body":"1. Перейдите в раздел **Документы**\n2. Нажмите **«Загрузить документ»** или перетащите файл в зону загрузки\n3. Укажите название и тип документа\n4. Нажмите **«Загрузить»**\n\nПоддерживаемые форматы: PDF, DOC, DOCX, TXT, JPG, PNG. Максимальный размер: 10 МБ."},{"heading":"Безопасность","body":"Все документы хранятся на защищённом сервере. Доступ к ним есть только у вас, вашего менеджера и администратора. Прямой доступ по URL без авторизации невозможен."}]',
 'Открыть Документы', '/agent/documents', 0),

-- agent-comms
('agent-comms', 'agent-chat', 'Как писать менеджеру', '2 мин',
 '[{"heading":"Веб-чат","body":"В разделе **Сообщения** вы видите список диалогов с менеджером. Нажмите на диалог, чтобы открыть чат. Введите сообщение и нажмите **Отправить**.\n\nМенеджер увидит ваше сообщение в своём кабинете."},{"heading":"Когда писать","body":"• Есть вопрос по лиду\n• Нужна помощь с документами\n• Хотите уточнить статус выплаты\n• Любые рабочие вопросы"}]',
 'Открыть Сообщения', '/agent/messages', 0),

('agent-comms', 'agent-telegram', 'Как подключить Telegram', '3 мин',
 '[{"heading":"Зачем Telegram","body":"Telegram позволяет:\n• Получать уведомления о статусах лидов и выплат\n• Общаться с менеджером, не заходя в платформу\n• Быстро отвечать на сообщения с телефона"},{"heading":"Как подключить","body":"1. Перейдите в **Профиль**\n2. В блоке «Telegram» нажмите **«Подключить Telegram»**\n3. Нажмите на появившуюся кнопку **«Открыть Telegram»**\n4. В Telegram нажмите **Start** в чате с ботом\n5. Готово — привязка выполнена"},{"heading":"Какие уведомления приходят","body":"• Новое сообщение от менеджера\n• Статус лида изменён\n• Выплата создана\n• Выплата оплачена или отклонена"},{"heading":"Как отключить","body":"В **Профиле** нажмите **«Отключить»** или напишите боту команду `/unlink`."}]',
 'Подключить Telegram', '/agent/profile', 1),

-- agent-faq
('agent-faq', 'agent-faq-list', 'FAQ агента', '4 мин',
 '[{"heading":"Как узнать размер моей комиссии?","body":"Размер комиссии устанавливается администратором в настройках платформы. По умолчанию это 30% от стоимости сделки. Когда лид переходит в статус «Закрыт (выигран)», выплата создаётся автоматически."},{"heading":"Могу ли я изменить статус лида?","body":"Нет. Статус лида меняет менеджер. Вы можете видеть текущий статус и историю изменений на странице лида."},{"heading":"Что делать, если выплата отклонена?","body":"Свяжитесь с менеджером через чат или Telegram. В карточке выплаты указана причина отклонения."},{"heading":"Как удалить лид?","body":"Агент не может удалить лид. Если лид был создан по ошибке, напишите менеджеру."},{"heading":"Могу ли я видеть лиды других агентов?","body":"Нет. Вы видите только свои лиды, свои выплаты и свои документы. Это сделано для конфиденциальности."},{"heading":"Что делать, если Telegram не подключается?","body":"1. Убедитесь, что вы нажимаете Start именно в чате с ботом @Agent_BFL_bot\n2. Попробуйте заново: в Профиле отключите и подключите Telegram повторно\n3. Если не помогает — напишите менеджеру"}]',
 NULL, NULL, 0);

