-- ─── MANAGER lessons ──────────────────────────────────

INSERT INTO learning_lessons (module_id, slug, title, duration, sections, next_action_label, next_action_href, sort_order) VALUES
-- manager-start
('manager-start', 'manager-overview', 'Обзор кабинета менеджера', '3 мин',
 '[{"heading":"Что вы видите после входа","body":"Дашборд менеджера показывает сводку по вашей работе: количество агентов, активные лиды, последние диалоги и ключевые метрики конверсии."},{"heading":"Навигация","body":"В левом меню:\n\n• **Дашборд** — сводка\n• **Агенты** — список ваших агентов\n• **Лиды** — все лиды с фильтрами\n• **Диалоги** — переписка с агентами\n• **Финансы** — выплаты\n• **Рассылки** — массовые сообщения\n• **Документы** — загруженные агентами файлы"}]',
 'Перейти к Агентам', '/manager/agents', 0),

('manager-start', 'manager-agents', 'Как работать с агентами', '3 мин',
 '[{"heading":"Список агентов","body":"В разделе **Агенты** вы видите всех агентов в системе: их статус, количество лидов, город, специализацию."},{"heading":"Карточка агента","body":"Нажмите на агента, чтобы увидеть детали:\n• Контактные данные\n• Статистика по лидам\n• Список лидов агента\n• Общий заработок"},{"heading":"Назначение агента на лид","body":"На странице лида нажмите **«Назначить агента»** и выберите агента из списка. После назначения агент увидит лид в своём кабинете."}]',
 'Открыть Агентов', '/manager/agents', 1),

-- manager-leads
('manager-leads', 'manager-lead-workflow', 'Воронка лидов', '4 мин',
 '[{"heading":"Жизненный цикл лида","body":"Каждый лид проходит воронку:\n\n**Новый** → **Контакт** → **Квалифицирован** → **Предложение** → **Переговоры** → **Закрыт (выигран)** или **Закрыт (проигран)**\n\nВы переводите лид по этапам, отражая реальный прогресс работы с клиентом."},{"heading":"Как сменить статус","body":"1. Перейдите в **Лиды** → откройте нужный лид\n2. В верхней части карточки выберите новый статус из выпадающего списка\n3. Статус обновится мгновенно\n\nВажно: при переводе в статус «Закрыт (выигран)» автоматически создаётся выплата агенту."},{"heading":"История изменений","body":"В правой части страницы лида отображается **История** — хронология всех изменений: создание, смена статуса, назначение агента. Это аудит-лог для прозрачности."}]',
 'Открыть Лиды', '/manager/leads', 0),

('manager-leads', 'manager-create-lead', 'Как создать лид', '2 мин',
 '[{"heading":"Создание лида менеджером","body":"Менеджер тоже может создавать лиды:\n\n1. **Лиды** → **«Новый лид»**\n2. Заполните данные клиента\n3. Сразу назначьте агента (опционально)\n4. Нажмите **«Создать»**\n\nЕсли агент не назначен, лид будет без привязки — его можно назначить позже."}]',
 'Создать лид', '/manager/leads', 1),

-- manager-comms
('manager-comms', 'manager-conversations', 'Диалоги с агентами', '3 мин',
 '[{"heading":"Список диалогов","body":"В разделе **Диалоги** отображаются все активные разговоры. Для каждого диалога видно:\n• Имя клиента (лида)\n• Канал (Web / Telegram)\n• Режим (Ручной / AI / Полуавто)\n• Статус (Активен / Ожидание / Эскалация / Закрыт)\n• Количество непрочитанных сообщений"},{"heading":"Telegram-диалоги","body":"Если агент подключил Telegram, диалог помечен значком **Telegram**. Когда вы пишете ответ в таком диалоге, сообщение **автоматически отправляется агенту в Telegram**. Агент может отвечать прямо из Telegram, не заходя на платформу."},{"heading":"Фильтры","body":"Используйте вкладки для фильтрации:\n• **Все** — все диалоги\n• **Активные** — текущие разговоры\n• **Эскалации** — требуют внимания"}]',
 'Открыть Диалоги', '/manager/conversations', 0),

('manager-comms', 'manager-broadcasts', 'Рассылки', '2 мин',
 '[{"heading":"Как отправить рассылку","body":"В разделе **Рассылки** вы можете отправить сообщение сразу всем агентам или группе. Это удобно для объявлений, обновлений и напоминаний."}]',
 'Открыть Рассылки', '/manager/broadcasts', 1),

-- manager-finance-docs
('manager-finance-docs', 'manager-payouts', 'Как работают выплаты', '3 мин',
 '[{"heading":"Автовыплаты","body":"Когда вы переводите лид в статус «Закрыт (выигран)», платформа автоматически создаёт выплату агенту. Сумма = стоимость сделки × ставка комиссии (по умолчанию 30%)."},{"heading":"Цикл выплаты","body":"**Ожидает** (создана) → **В обработке** (взята администратором) → **Оплачено** или **Отклонено**\n\nМенеджер видит выплаты в разделе Финансы, но **одобряет их только администратор**."},{"heading":"Что видит менеджер","body":"В разделе **Финансы** вы видите все выплаты ваших агентов: суммы, статусы, даты. Это помогает контролировать мотивацию агентов."}]',
 'Открыть Финансы', '/manager/finance', 0),

('manager-finance-docs', 'manager-documents', 'Документы агентов', '2 мин',
 '[{"heading":"Просмотр документов","body":"В разделе **Документы** отображаются все файлы, загруженные агентами: договоры, акты, доверенности. Вы можете скачать любой документ."},{"heading":"Безопасность","body":"Документы доступны только авторизованным пользователям с соответствующей ролью. Скачивание происходит через защищённый API с проверкой токена."}]',
 'Открыть Документы', '/manager/documents', 1),

-- manager-faq
('manager-faq', 'manager-faq-list', 'FAQ менеджера', '4 мин',
 '[{"heading":"Могу ли я одобрить выплату?","body":"Нет. Выплаты одобряет только администратор. Менеджер видит их статус, но не может менять."},{"heading":"Как изменить ставку комиссии?","body":"Ставку комиссии устанавливает администратор в разделе **Настройки**. По умолчанию 30%."},{"heading":"Что делать, если агент не отвечает в чате?","body":"Проверьте, подключён ли у агента Telegram. Если да — отправьте сообщение через платформу, оно придёт в Telegram. Если нет — свяжитесь по телефону."},{"heading":"Можно ли переназначить лид другому агенту?","body":"Да. На странице лида нажмите «Назначить агента» и выберите другого агента."},{"heading":"Как понять, что диалог идёт через Telegram?","body":"В списке диалогов рядом с именем клиента есть badge канала: «Web» или «Telegram». Telegram-диалоги помечены синим значком."}]',
 NULL, NULL, 0);

