-- ─── ADMIN lessons ────────────────────────────────────

INSERT INTO learning_lessons (module_id, slug, title, duration, sections, next_action_label, next_action_href, sort_order) VALUES
-- admin-start
('admin-start', 'admin-overview', 'Обзор кабинета администратора', '3 мин',
 '[{"heading":"Роль администратора","body":"Администратор — владелец платформы. Вы управляете пользователями, ролями, настройками, интеграциями, выплатами и видите полную картину системы."},{"heading":"Навигация","body":"В левом меню:\n\n• **Дашборд** — системная статистика\n• **Пользователи** — все пользователи, роли, статусы\n• **Финансы** — одобрение/отклонение выплат\n• **Роли** — управление ролями\n• **Настройки** — параметры платформы\n• **Интеграции** — Telegram Bot\n• **Логи** — аудит действий"}]',
 'Открыть Дашборд', '/admin/dashboard', 0),

('admin-start', 'admin-users', 'Управление пользователями', '3 мин',
 '[{"heading":"Список пользователей","body":"В разделе **Пользователи** вы видите всех: агентов, менеджеров, других администраторов. Для каждого показаны: имя, email, телефон, роль, статус, дата регистрации."},{"heading":"Действия с пользователем","body":"Вы можете:\n• **Изменить роль** — переназначить агента менеджером и наоборот\n• **Заблокировать** — запретить вход в систему\n• **Активировать** — вернуть доступ заблокированному пользователю"}]',
 'Открыть Пользователей', '/admin/users', 1),

('admin-start', 'admin-settings', 'Настройки платформы', '2 мин',
 '[{"heading":"Доступные настройки","body":"В разделе **Настройки** можно изменить ключевые параметры:\n\n• **commission_rate** — ставка комиссии агента (по умолчанию 0.3 = 30%)\n• Другие параметры, которые могут добавляться по мере развития платформы"},{"heading":"Как изменить настройку","body":"Нажмите на настройку → измените значение → сохраните. Изменения вступают в силу немедленно."}]',
 'Открыть Настройки', '/admin/settings', 2),

-- admin-finance
('admin-finance', 'admin-payout-flow', 'Управление выплатами', '4 мин',
 '[{"heading":"Как создаются выплаты","body":"Выплаты создаются **автоматически**, когда менеджер переводит лид в статус «Закрыт (выигран)». Вы не создаёте выплаты вручную — только одобряете или отклоняете."},{"heading":"State machine выплат","body":"Выплата проходит через строгую машину состояний:\n\n• **Ожидает** → «В обработку» или «Отклонить»\n• **В обработке** → «Оплачено» или «Отклонить»\n• **Оплачено** — финальное состояние\n• **Отклонено** — финальное состояние\n\nНевозможно вернуть оплаченную или отклонённую выплату обратно."},{"heading":"Как одобрить выплату","body":"1. Перейдите в **Финансы**\n2. Найдите выплату со статусом «Ожидает»\n3. Нажмите **«В обработку»** → затем **«Оплачено»**\n\nАгент получит уведомление в Telegram о смене статуса."},{"heading":"Как отклонить выплату","body":"1. Найдите выплату\n2. Нажмите **«Отклонить»**\n3. Укажите причину отклонения\n\nАгент увидит причину в своём кабинете и получит уведомление."}]',
 'Открыть Финансы', '/admin/finance', 0),

-- admin-integrations
('admin-integrations', 'admin-telegram', 'Telegram интеграция', '4 мин',
 '[{"heading":"Как устроена интеграция","body":"Платформа подключена к Telegram-боту (@Agent_BFL_bot). Бот позволяет агентам:\n• Получать уведомления\n• Общаться с менеджером из Telegram\n\nBот не заменяет платформу — он является транспортным каналом."},{"heading":"Настройка","body":"В разделе **Интеграции** вы видите:\n• Статус бота (подключён/не подключён)\n• URL webhook\n• Количество подключённых агентов\n• Имя бота\n\nBot token хранится в переменной окружения `TELEGRAM_BOT_TOKEN` на сервере."},{"heading":"Webhook","body":"Webhook — это URL, по которому Telegram отправляет входящие сообщения на вашу платформу. Он устанавливается один раз при настройке. URL:\n\n`https://ваш-домен/api/telegram/webhook`\n\nЕсли webhook сбился, нажмите **«Настроить webhook»** в разделе Интеграции."},{"heading":"Мониторинг","body":"Если агент не получает уведомления:\n1. Проверьте, привязан ли его Telegram (раздел Пользователи → агент)\n2. Проверьте логи (раздел Логи)\n3. Проверьте статус webhook в Интеграциях"}]',
 'Открыть Интеграции', '/admin/integrations', 0),

-- admin-monitoring
('admin-monitoring', 'admin-logs', 'Логи и аудит', '3 мин',
 '[{"heading":"Аудит-логи","body":"В разделе **Логи** отображаются все значимые действия в системе:\n• Регистрации и входы\n• Создание и изменение лидов\n• Смены статусов\n• Одобрение/отклонение выплат\n• Привязка/отвязка Telegram"},{"heading":"Что отслеживается","body":"Для каждого события записывается:\n• **Действие** — что произошло\n• **Пользователь** — кто сделал\n• **Детали** — подробности (JSON)\n• **Уровень** — info / warning / error\n• **Дата и время**"},{"heading":"Зачем это нужно","body":"Аудит-логи помогают:\n• Разбирать спорные ситуации\n• Отслеживать подозрительную активность\n• Контролировать работу менеджеров и агентов\n• Выявлять ошибки интеграций"}]',
 'Открыть Логи', '/admin/logs', 0),

-- admin-faq
('admin-faq', 'admin-faq-list', 'FAQ администратора', '4 мин',
 '[{"heading":"Как добавить нового менеджера?","body":"Новый менеджер регистрируется через страницу регистрации. После регистрации он получает роль «Агент» по умолчанию. Перейдите в **Пользователи** → найдите его → измените роль на «Менеджер»."},{"heading":"Как изменить ставку комиссии?","body":"**Настройки** → найдите параметр `commission_rate` → измените значение (0.3 = 30%, 0.25 = 25% и т.д.) → сохраните."},{"heading":"Как заблокировать пользователя?","body":"**Пользователи** → найдите пользователя → нажмите «Заблокировать». Пользователь не сможет войти в систему."},{"heading":"Что если Telegram-бот не работает?","body":"1. Проверьте **Интеграции** → статус webhook\n2. Проверьте **Логи** → ищите ошибки с типом «error»\n3. Убедитесь, что `TELEGRAM_BOT_TOKEN` корректен в .env.local\n4. Попробуйте переустановить webhook через кнопку «Настроить webhook»"},{"heading":"Можно ли отменить выплату после оплаты?","body":"Нет. Статусы «Оплачено» и «Отклонено» являются финальными. Это сделано намеренно для прозрачности и защиты от ошибок."}]',
 NULL, NULL, 0);

